21	/***********************************************************************
22	 * dboard key class to use for look-up
23	 **********************************************************************/
24	class dboard_key_t
25	{
26	public:
27	    dboard_key_t(const dboard_id_t& id = dboard_id_t::none(), bool restricted = false)
28	        : _rx_id(id), _tx_id(id), _xcvr(false), _restricted(restricted)
29	    {
30	    }
31	
32	    dboard_key_t(
33	        const dboard_id_t& rx_id, const dboard_id_t& tx_id, bool restricted = false)
34	        : _rx_id(rx_id), _tx_id(tx_id), _xcvr(true), _restricted(restricted)
35	    {
36	    }
37	
38	    dboard_id_t xx_id(void) const
39	    {
40	        UHD_ASSERT_THROW(not this->is_xcvr());
41	        return this->_rx_id;
42	    }
43	
44	    dboard_id_t rx_id(void) const
45	    {
46	        UHD_ASSERT_THROW(this->is_xcvr());
47	        return this->_rx_id;
48	    }
49	
50	    dboard_id_t tx_id(void) const
51	    {
52	        UHD_ASSERT_THROW(this->is_xcvr());
53	        return this->_tx_id;
54	    }
55	
56	    bool is_xcvr(void) const
57	    {
58	        return this->_xcvr;
59	    }
60	
61	    bool is_restricted(void) const
62	    {
63	        return this->_restricted;
64	    }
65	
66	private:
67	    dboard_id_t _rx_id, _tx_id;
68	    bool _xcvr;
69	    bool _restricted;
70	};
71	
72	bool operator==(const dboard_key_t& lhs, const dboard_key_t& rhs)
73	{
74	    if (lhs.is_xcvr() and rhs.is_xcvr())
75	        return lhs.rx_id() == rhs.rx_id() and lhs.tx_id() == rhs.tx_id();
76	    if (not lhs.is_xcvr() and not rhs.is_xcvr())
77	        return lhs.xx_id() == rhs.xx_id();
78	    return false;
79	}
