81	/***********************************************************************
82	 * storage and registering for dboards
83	 **********************************************************************/
84	// dboard registry tuple: dboard constructor, canonical name, subdev names, container
85	// constructor
86	typedef std::tuple<dboard_manager::dboard_ctor_t,
87	    std::string,
88	    std::vector<std::string>,
89	    dboard_manager::dboard_ctor_t>
90	    args_t;
91	
92	// map a dboard id to a dboard constructor
93	typedef uhd::dict<dboard_key_t, args_t> id_to_args_map_t;
94	UHD_SINGLETON_FCN(id_to_args_map_t, get_id_to_args_map)
95	
96	static void register_dboard_key(const dboard_key_t& dboard_key,
97	    dboard_manager::dboard_ctor_t db_subdev_ctor,
98	    const std::string& name,
99	    const std::vector<std::string>& subdev_names,
100	    dboard_manager::dboard_ctor_t db_container_ctor)
101	{
102	    // UHD_LOGGER_TRACE("DBMGR") << "registering: " << name;
103	    if (get_id_to_args_map().has_key(dboard_key)) {
104	        if (dboard_key.is_xcvr())
105	            throw uhd::key_error(str(
106	                boost::format("The dboard id pair [%s, %s] is already registered to %s.")
107	                % dboard_key.rx_id().to_string() % dboard_key.tx_id().to_string()
108	                % std::get<1>(get_id_to_args_map()[dboard_key])));
109	
110	        else
111	            throw uhd::key_error(
112	                str(boost::format("The dboard id %s is already registered to %s.")
113	                    % dboard_key.xx_id().to_string()
114	                    % std::get<1>(get_id_to_args_map()[dboard_key])));
115	    }
116	    get_id_to_args_map()[dboard_key] =
117	        args_t(db_subdev_ctor, name, subdev_names, db_container_ctor);
118	}
119	
120	void dboard_manager::register_dboard(const dboard_id_t& dboard_id,
121	    dboard_ctor_t db_subdev_ctor,
122	    const std::string& name,
123	    const std::vector<std::string>& subdev_names,
124	    dboard_ctor_t db_container_ctor)
125	{
126	    register_dboard_key(
127	        dboard_key_t(dboard_id), db_subdev_ctor, name, subdev_names, db_container_ctor);
128	}
129	
130	void dboard_manager::register_dboard(const dboard_id_t& rx_dboard_id,
131	    const dboard_id_t& tx_dboard_id,
132	    dboard_ctor_t db_subdev_ctor,
133	    const std::string& name,
134	    const std::vector<std::string>& subdev_names,
135	    dboard_ctor_t db_container_ctor)
136	{
137	    register_dboard_key(dboard_key_t(rx_dboard_id, tx_dboard_id),
138	        db_subdev_ctor,
139	        name,
140	        subdev_names,
141	        db_container_ctor);
142	}
