144	void dboard_manager::register_dboard_restricted(const dboard_id_t& dboard_id,
145	    dboard_ctor_t db_subdev_ctor,
146	    const std::string& name,
147	    const std::vector<std::string>& subdev_names,
148	    dboard_ctor_t db_container_ctor)
149	{
150	    register_dboard_key(dboard_key_t(dboard_id, true),
151	        db_subdev_ctor,
