157	void dboard_manager::register_dboard_restricted(const dboard_id_t& rx_dboard_id,
158	    const dboard_id_t& tx_dboard_id,
159	    dboard_ctor_t db_subdev_ctor,
160	    const std::string& name,
161	    const std::vector<std::string>& subdev_names,
162	    dboard_ctor_t db_container_ctor)
