170	
171	std::string dboard_id_t::to_cname(void) const
172	{
173	    std::string cname;
174	    for (const dboard_key_t& key : get_id_to_args_map().keys()) {
175	        if ((not key.is_xcvr() and *this == key.xx_id())
176	            or (key.is_xcvr() and (*this == key.rx_id() or *this == key.tx_id()))) {
177	            if (not cname.empty())
178	                cname += ", ";
179	            cname += std::get<1>(get_id_to_args_map()[key]);
180	        }
181	    }
182	    return (cname.empty()) ? "Unknown" : cname;
183	}
184	
185	std::string dboard_id_t::to_pp_string(void) const
186	{
187	    return str(boost::format("%s (%s)") % this->to_cname() % this->to_string());
188	}
