190	/***********************************************************************
191	 * dboard manager implementation class
192	 **********************************************************************/
193	class dboard_manager_impl : public dboard_manager
194	{
195	public:
196	    dboard_manager_impl(dboard_eeprom_t rx_eeprom,
197	        dboard_eeprom_t tx_eeprom,
198	        dboard_iface::sptr iface,
199	        property_tree::sptr subtree,
200	        bool defer_db_init);
201	    ~dboard_manager_impl(void) override;
202	
203	    inline const std::vector<std::string>& get_rx_frontends() const override
204	    {
205	        return _rx_frontends;
206	    }
207	
208	    inline const std::vector<std::string>& get_tx_frontends() const override
209	    {
210	        return _tx_frontends;
211	    }
212	
213	    void initialize_dboards() override;
214	
215	private:
216	    void init(dboard_eeprom_t, dboard_eeprom_t, property_tree::sptr, bool);
217	    // list of rx and tx dboards in this dboard_manager
218	    // each dboard here is actually a subdevice proxy
219	    // the subdevice proxy is internal to the cpp file
220	    uhd::dict<std::string, dboard_base::sptr> _rx_dboards;
221	    uhd::dict<std::string, dboard_base::sptr> _tx_dboards;
222	    std::vector<dboard_base::sptr> _rx_containers;
223	    std::vector<dboard_base::sptr> _tx_containers;
224	    std::vector<std::string> _rx_frontends;
225	    std::vector<std::string> _tx_frontends;
226	    dboard_iface::sptr _iface;
227	    void set_nice_dboard_if(void);
228	};
229	
230	/***********************************************************************
231	 * make routine for dboard manager
232	 **********************************************************************/
233	dboard_manager::sptr dboard_manager::make(dboard_id_t rx_dboard_id,
234	    dboard_id_t tx_dboard_id,
235	    dboard_id_t gdboard_id,
236	    dboard_iface::sptr iface,
237	    property_tree::sptr subtree,
238	    bool defer_db_init)
239	{
240	    dboard_eeprom_t rx_eeprom;
241	    dboard_eeprom_t tx_eeprom;
242	    rx_eeprom.id = rx_dboard_id;
243	    tx_eeprom.id = (gdboard_id == dboard_id_t::none()) ? tx_dboard_id : gdboard_id;
244	    return dboard_manager::sptr(
245	        new dboard_manager_impl(rx_eeprom, tx_eeprom, iface, subtree, defer_db_init));
246	}
247	
248	dboard_manager::sptr dboard_manager::make(dboard_eeprom_t rx_eeprom,
249	    dboard_eeprom_t tx_eeprom,
250	    dboard_eeprom_t gdb_eeprom,
251	    dboard_iface::sptr iface,
252	    property_tree::sptr subtree,
253	    bool defer_db_init)
254	{
255	    return dboard_manager::sptr(new dboard_manager_impl(rx_eeprom,
256	        (gdb_eeprom.id == dboard_id_t::none()) ? tx_eeprom : gdb_eeprom,
257	        iface,
258	        subtree,
259	        defer_db_init));
260	}
261	
262	/***********************************************************************
263	 * implementation class methods
264	 **********************************************************************/
265	dboard_manager_impl::dboard_manager_impl(dboard_eeprom_t rx_eeprom,
266	    dboard_eeprom_t tx_eeprom,
267	    dboard_iface::sptr iface,
268	    property_tree::sptr subtree,
269	    bool defer_db_init)
270	    : _iface(iface)
271	{
272	    try {
273	        this->init(rx_eeprom, tx_eeprom, subtree, defer_db_init);
274	    } catch (const std::exception& e) {
275	        UHD_LOGGER_ERROR("DBMGR") << boost::format(
276	            "The daughterboard manager encountered a recoverable error in init.\n"
277	            "Loading the \"unknown\" daughterboard implementations to continue.\n"
278	            "The daughterboard cannot operate until this error is resolved.\n")
279	                                  << e.what();
280	        // clean up the stuff added by the call above
281	        if (subtree->exists("rx_frontends"))
282	            subtree->remove("rx_frontends");
283	        if (subtree->exists("tx_frontends"))
284	            subtree->remove("tx_frontends");
285	        if (subtree->exists("iface"))
286	            subtree->remove("iface");
287	        dboard_eeprom_t dummy_eeprom;
288	        dummy_eeprom.id = dboard_id_t::none();
289	        this->init(dummy_eeprom, dummy_eeprom, subtree, false);
290	    }
291	}
292	
293	void dboard_manager_impl::init(dboard_eeprom_t rx_eeprom,
294	    dboard_eeprom_t tx_eeprom,
295	    property_tree::sptr subtree,
296	    bool defer_db_init)
297	{
298	    // find the dboard key matches for the dboard ids
299	    dboard_key_t rx_dboard_key, tx_dboard_key, xcvr_dboard_key;
300	    for (const dboard_key_t& key : get_id_to_args_map().keys()) {
301	        if (key.is_xcvr()) {
302	            if (rx_eeprom.id == key.rx_id() and tx_eeprom.id == key.tx_id())
303	                xcvr_dboard_key = key;
304	            if (rx_eeprom.id == key.rx_id())
305	                rx_dboard_key = key; // kept to handle warning
306	            if (rx_eeprom.id == key.tx_id())
307	                tx_dboard_key = key; // kept to handle warning
308	        } else {
309	            if (rx_eeprom.id == key.xx_id())
310	                rx_dboard_key = key;
311	            if (tx_eeprom.id == key.xx_id())
312	                tx_dboard_key = key;
313	        }
314	    }
315	
316	    // warn for invalid dboard id xcvr combinations
317	    if (not xcvr_dboard_key.is_xcvr()
318	        and (rx_dboard_key.is_xcvr() or tx_dboard_key.is_xcvr())) {
319	        UHD_LOGGER_WARNING("DBMGR")
320	            << boost::format("Unknown transceiver board ID combination.\n"
321	                             "Is your daughter-board mounted properly?\n"
322	                             "RX dboard ID: %s\n"
323	                             "TX dboard ID: %s\n")
324	                   % rx_eeprom.id.to_pp_string() % tx_eeprom.id.to_pp_string();
325	    }
326	
327	    // initialize the gpio pins before creating subdevs
328	    set_nice_dboard_if();
329	
330	    // conditionally register the dboard iface in the tree
331	    if (not(rx_dboard_key.is_restricted() or tx_dboard_key.is_restricted()
332	            or xcvr_dboard_key.is_restricted())) {
333	        subtree->create<dboard_iface::sptr>("iface").set(_iface);
334	    }
335	
336	    // dboard constructor args
337	    dboard_ctor_args_t db_ctor_args;
338	    db_ctor_args.db_iface = _iface;
339	
340	    // make xcvr subdevs
341	    if (xcvr_dboard_key.is_xcvr()) {
342	        // extract data for the xcvr dboard key
343	        dboard_ctor_t subdev_ctor;
344	        std::string name;
345	        std::vector<std::string> subdevs;
346	        dboard_ctor_t container_ctor;
347	        std::tie(subdev_ctor, name, subdevs, container_ctor) =
348	            get_id_to_args_map()[xcvr_dboard_key];
349	
350	        // create the container class.
351	        // a container class exists per N subdevs registered in a register_dboard* call
352	        db_ctor_args.sd_name   = "common";
353	        db_ctor_args.rx_eeprom = rx_eeprom;
354	        db_ctor_args.tx_eeprom = tx_eeprom;
355	        db_ctor_args.rx_subtree =
356	            subtree->subtree("rx_frontends/" + db_ctor_args.sd_name);
357	        db_ctor_args.tx_subtree =
358	            subtree->subtree("tx_frontends/" + db_ctor_args.sd_name);
359	        if (container_ctor) {
360	            db_ctor_args.rx_container = container_ctor(&db_ctor_args);
361	        } else {
362	            db_ctor_args.rx_container = dboard_base::sptr();
363	        }
364	        db_ctor_args.tx_container = db_ctor_args.rx_container; // Same TX and RX container
365	
366	        // create the xcvr object for each subdevice
367	        for (const std::string& subdev : subdevs) {
368	            db_ctor_args.sd_name = subdev;
369	            db_ctor_args.rx_subtree =
370	                subtree->subtree("rx_frontends/" + db_ctor_args.sd_name);
371	            db_ctor_args.tx_subtree =
372	                subtree->subtree("tx_frontends/" + db_ctor_args.sd_name);
373	            dboard_base::sptr xcvr_dboard = subdev_ctor(&db_ctor_args);
374	            _rx_dboards[subdev]           = xcvr_dboard;
375	            _tx_dboards[subdev]           = xcvr_dboard;
376	            xcvr_dboard->initialize();
377	        }
378	
379	        // initialize the container after all subdevs have been created
380	        if (container_ctor) {
381	            if (defer_db_init) {
382	                _rx_containers.push_back(db_ctor_args.rx_container);
383	            } else {
384	                db_ctor_args.rx_container->initialize();
385	            }
386	        }
387	
388	        // Populate frontend names in-order.
389	        // We cannot use _xx_dboards.keys() here because of the ordering requirement
390	        _rx_frontends = subdevs;
391	        _tx_frontends = subdevs;
392	    }
393	
394	    // make tx and rx subdevs (separate subdevs for rx and tx dboards)
395	    else {
396	        // force the rx key to the unknown board for bad combinations
397	        if (rx_dboard_key.is_xcvr() or rx_dboard_key.xx_id() == dboard_id_t::none()) {
398	            rx_dboard_key = dboard_key_t(0xfff1);
399	        }
400	
401	        // extract data for the rx dboard key
402	        dboard_ctor_t rx_dboard_ctor;
403	        std::string rx_name;
404	        std::vector<std::string> rx_subdevs;
405	        dboard_ctor_t rx_cont_ctor;
406	        std::tie(rx_dboard_ctor, rx_name, rx_subdevs, rx_cont_ctor) =
407	            get_id_to_args_map()[rx_dboard_key];
408	
409	        // create the container class.
410	        // a container class exists per N subdevs registered in a register_dboard* call
411	        db_ctor_args.sd_name      = "common";
412	        db_ctor_args.rx_eeprom    = rx_eeprom;
413	        db_ctor_args.tx_eeprom.id = dboard_id_t::none();
414	        db_ctor_args.rx_subtree =
415	            subtree->subtree("rx_frontends/" + db_ctor_args.sd_name);
416	        db_ctor_args.tx_subtree = property_tree::sptr();
417	        if (rx_cont_ctor) {
418	            db_ctor_args.rx_container = rx_cont_ctor(&db_ctor_args);
419	        } else {
420	            db_ctor_args.rx_container = dboard_base::sptr();
421	        }
422	
423	        // make the rx subdevs
424	        for (const std::string& subdev : rx_subdevs) {
425	            db_ctor_args.sd_name = subdev;
426	            db_ctor_args.rx_subtree =
427	                subtree->subtree("rx_frontends/" + db_ctor_args.sd_name);
428	            _rx_dboards[subdev] = rx_dboard_ctor(&db_ctor_args);
429	            _rx_dboards[subdev]->initialize();
430	        }
431	
432	        // initialize the container after all subdevs have been created
433	        if (rx_cont_ctor) {
434	            if (defer_db_init) {
435	                _rx_containers.push_back(db_ctor_args.rx_container);
436	            } else {
437	                db_ctor_args.rx_container->initialize();
438	            }
439	        }
440	
441	        // force the tx key to the unknown board for bad combinations
442	        if (tx_dboard_key.is_xcvr() or tx_dboard_key.xx_id() == dboard_id_t::none()) {
443	            tx_dboard_key = dboard_key_t(0xfff0);
444	        }
445	
446	        // extract data for the tx dboard key
447	        dboard_ctor_t tx_dboard_ctor;
448	        std::string tx_name;
449	        std::vector<std::string> tx_subdevs;
450	        dboard_ctor_t tx_cont_ctor;
451	        std::tie(tx_dboard_ctor, tx_name, tx_subdevs, tx_cont_ctor) =
452	            get_id_to_args_map()[tx_dboard_key];
453	
454	        // create the container class.
455	        // a container class exists per N subdevs registered in a register_dboard* call
456	        db_ctor_args.sd_name      = "common";
457	        db_ctor_args.rx_eeprom.id = dboard_id_t::none();
458	        db_ctor_args.tx_eeprom    = tx_eeprom;
459	        db_ctor_args.rx_subtree   = property_tree::sptr();
460	        db_ctor_args.tx_subtree =
461	            subtree->subtree("tx_frontends/" + db_ctor_args.sd_name);
462	        if (tx_cont_ctor) {
463	            db_ctor_args.tx_container = tx_cont_ctor(&db_ctor_args);
464	        } else {
465	            db_ctor_args.tx_container = dboard_base::sptr();
466	        }
467	
468	        // make the tx subdevs
469	        for (const std::string& subdev : tx_subdevs) {
470	            db_ctor_args.sd_name = subdev;
471	            db_ctor_args.tx_subtree =
472	                subtree->subtree("tx_frontends/" + db_ctor_args.sd_name);
473	            _tx_dboards[subdev] = tx_dboard_ctor(&db_ctor_args);
474	            _tx_dboards[subdev]->initialize();
475	        }
476	
477	        // initialize the container after all subdevs have been created
478	        if (tx_cont_ctor) {
479	            if (defer_db_init) {
480	                _tx_containers.push_back(db_ctor_args.tx_container);
481	            } else {
482	                db_ctor_args.tx_container->initialize();
483	            }
484	        }
485	
486	        // Populate frontend names in-order.
487	        // We cannot use _xx_dboards.keys() here because of the ordering requirement
488	        _rx_frontends = rx_subdevs;
489	        _tx_frontends = tx_subdevs;
490	    }
491	}
492	
493	void dboard_manager_impl::initialize_dboards(void)
494	{
495	    for (dboard_base::sptr& _rx_container : _rx_containers) {
496	        _rx_container->initialize();
497	    }
498	
499	    for (dboard_base::sptr& _tx_container : _tx_containers) {
500	        _tx_container->initialize();
501	    }
502	}
503	
504	dboard_manager_impl::~dboard_manager_impl(void)
505	{
506	    UHD_SAFE_CALL(set_nice_dboard_if());
507	}
508	
509	void dboard_manager_impl::set_nice_dboard_if(void)
510	{
511	    // make a list of possible unit types
512	    const std::vector<dboard_iface::unit_t> units{
513	        dboard_iface::UNIT_RX, dboard_iface::UNIT_TX};
514	
515	    // set nice settings on each unit
516	    for (dboard_iface::unit_t unit : units) {
517	        _iface->set_gpio_ddr(unit, 0x0000); // all inputs
518	        _iface->set_gpio_out(unit, 0x0000); // all low
519	        _iface->set_pin_ctrl(unit, 0x0000); // all gpio
520	        _iface->set_clock_enabled(unit, false); // clock off
521	    }
522	}
