42	{
43	    /* NOP */
44	}
45	
46	class rx_dsp_core_3000_impl : public rx_dsp_core_3000
47	{
48	public:
49	    rx_dsp_core_3000_impl(wb_iface::sptr iface, const size_t dsp_base, const bool is_b200)
50	        : _iface(iface), _dsp_base(dsp_base), _is_b200(is_b200)
51	    {
52	    }
53	
54	    ~rx_dsp_core_3000_impl(void) override
55	    {
56	        UHD_SAFE_CALL(; // NOP
57	        )
58	    }
59	
60	    void set_mux(const uhd::usrp::fe_connection_t& fe_conn) override
61	    {
62	        uint32_t reg_val = 0;
63	        switch (fe_conn.get_sampling_mode()) {
64	            case uhd::usrp::fe_connection_t::REAL:
65	            case uhd::usrp::fe_connection_t::HETERODYNE:
66	                reg_val = FLAG_DSP_RX_MUX_REAL_MODE;
67	                break;
68	            default:
69	                reg_val = 0;
70	                break;
71	        }
72	
73	        if (fe_conn.is_iq_swapped())
74	            reg_val |= FLAG_DSP_RX_MUX_SWAP_IQ;
75	        if (fe_conn.is_i_inverted())
76	            reg_val |= FLAG_DSP_RX_MUX_INVERT_I;
77	        if (fe_conn.is_q_inverted())
78	            reg_val |= FLAG_DSP_RX_MUX_INVERT_Q;
79	
80	        _iface->poke32(REG_DSP_RX_MUX, reg_val);
81	
82	        if (fe_conn.get_sampling_mode() == uhd::usrp::fe_connection_t::HETERODYNE) {
83	            // 1. Remember the IF frequency
84	            const double fe_if_freq = fe_conn.get_if_freq();
85	            // 2. Map IF frequency to the range [0, _tick_rate)
86	            double if_freq = std::abs(std::fmod(fe_if_freq, _tick_rate));
87	            // 3. Map IF frequency to the range [-_tick_rate/2, _tick_rate/2]
88	            //   This is the aliased frequency
89	            if (if_freq > (_tick_rate / 2.0)) {
90	                if_freq -= _tick_rate;
91	            }
92	            // 4. Set DSP offset to spin the signal in the opposite
93	            //   direction as the aliased frequency
94	            if (!std::signbit(fe_if_freq)) {
95	                if_freq *= -1.0;
96	            }
97	            _dsp_freq_offset = if_freq;
98	        } else {
99	            _dsp_freq_offset = 0.0;
100	        }
101	    }
102	
103	    void set_tick_rate(const double rate) override
104	    {
105	        _tick_rate = rate;
106	        set_freq(_current_freq);
107	    }
108	
109	    void set_link_rate(const double rate) override
110	    {
111	        //_link_rate = rate/sizeof(uint32_t); //in samps/s
112	        _link_rate = rate / sizeof(uint16_t); // in samps/s (allows for 8sc)
113	    }
114	
115	    uhd::meta_range_t get_host_rates(void) override
116	    {
117	        meta_range_t range;
118	        if (!_is_b200) {
119	            for (int rate = 1024; rate > 512; rate -= 8) {
120	                range.push_back(range_t(_tick_rate / rate));
121	            }
122	        }
123	        for (int rate = 512; rate > 256; rate -= 4) {
124	            range.push_back(range_t(_tick_rate / rate));
125	        }
126	        for (int rate = 256; rate > 128; rate -= 2) {
127	            range.push_back(range_t(_tick_rate / rate));
128	        }
129	        for (int rate = 128; rate >= int(std::ceil(_tick_rate / _link_rate)); rate -= 1) {
130	            range.push_back(range_t(_tick_rate / rate));
131	        }
132	        return range;
133	    }
134	
135	    double set_host_rate(const double rate) override
136	    {
137	        const size_t decim_rate =
138	            std::lround(_tick_rate / this->get_host_rates().clip(rate, true));
139	        size_t decim = decim_rate;
140	
141	        // determine which half-band filters are activated
142	        int hb0 = 0, hb1 = 0, hb2 = 0, hb_enable = 0;
143	        if (decim % 2 == 0) {
144	            hb0 = 1;
145	            decim /= 2;
146	        }
147	        if (decim % 2 == 0) {
148	            hb1 = 1;
149	            decim /= 2;
150	        }
151	        // the third half-band is not supported by the B200
152	        if (decim % 2 == 0 && !_is_b200) {
153	            hb2 = 1;
154	            decim /= 2;
155	        }
156	
157	        if (_is_b200) {
158	            _iface->poke32(REG_DSP_RX_DECIM,
159	                (hb0 << 9) /*small HB */ | (hb1 << 8) /*large HB*/ | (decim & 0xff));
160	
161	            if (decim > 1 and hb0 == 0 and hb1 == 0) {
162	                UHD_LOGGER_WARNING("CORES")
163	                    << "The requested decimation is odd; the user should expect CIC "
164	                       "rolloff.\n"
165	                       "Select an even decimation to ensure that a halfband filter "
166	                       "is enabled.\n"
167	                    << decim_rate << " = (" << (_tick_rate / 1e6) << " MHz)/("
168	                    << (rate / 1e6) << " MHz)\n";
169	            }
170	        } else {
171	            // Encode Halfband config for setting register programming.
172	            if (hb2) { // Implies HB1 and HB0 also asserted
173	                hb_enable = 3;
174	            } else if (hb1) { // Implies HB0 is also asserted
175	                hb_enable = 2;
176	            } else if (hb0) {
177	                hb_enable = 1;
178	            } else {
179	                hb_enable = 0;
180	            }
181	            _iface->poke32(REG_DSP_RX_DECIM, (hb_enable << 8) | (decim & 0xff));
182	
183	            if (decim > 1 and hb0 == 0 and hb1 == 0 and hb2 == 0) {
184	                UHD_LOGGER_WARNING("CORES")
185	                    << "The requested decimation is odd; the user should expect "
186	                       "passband CIC rolloff.\n"
187	                       "Select an even decimation to ensure that a halfband filter "
188	                       "is enabled.\n"
189	                       "Decimations factorable by 4 will enable 2 halfbands, those "
190	                       "factorable by 8 will enable 3 halfbands.\n"
191	                       "decimation = dsp_rate/samp_rate -> "
192	                    << decim_rate << " = (" << (_tick_rate / 1e6) << " MHz)/("
193	                    << (rate / 1e6) << " MHz)\n";
194	            }
195	        }
196	
197	        // Caclulate algorithmic gain of CIC for a given decimation.
198	        // For Ettus CIC R=decim, M=1, N=4. Gain = (R * M) ^ N
199	        const double rate_pow = std::pow(double(decim & 0xff), 4);
200	        // Calculate compensation gain values for algorithmic gain of CORDIC and CIC
201	        // taking into account gain compensation blocks already hardcoded in place in DDC
202	        // (that provide simple 1/2^n gain compensation). CORDIC algorithmic gain limits
203	        // asymptotically around 1.647 after many iterations.
204	        //
205	        // The polar rotation of [I,Q] = [1,1] by Pi/8 also yields max magnitude of
206	        // SQRT(2) (~1.4142) however input to the CORDIC thats outside the unit circle can
207	        // only be sourced from a saturated RF frontend. To provide additional dynamic
208	        // range head room accordingly using scale factor applied at egress from DDC would
209	        // cost us small signal performance, thus we do no provide compensation gain for a
210	        // saturated front end and allow the signal to clip in the H/W as needed. If we
211	        // wished to avoid the signal clipping in these circumstances then adjust code to
212	        // read: _scaling_adjustment = std::pow(2,
213	        // ceil_log2(rate_pow))/(1.648*rate_pow*1.415);
214	        _scaling_adjustment = std::pow(2, ceil_log2(rate_pow)) / (1.648 * rate_pow);
215	
216	        this->update_scalar();
217	
218	        return _tick_rate / decim_rate;
219	    }
220	
221	    // Calculate compensation gain values for algorithmic gain of CORDIC and CIC taking
222	    // into account gain compensation blocks already hardcoded in place in DDC (that
223	    // provide simple 1/2^n gain compensation). Further more factor in OTW format which
224	    // adds further gain factor to weight output samples correctly.
225	    void update_scalar(void)
226	    {
227	        const double target_scalar =
228	            (1 << (_is_b200 ? 16 : 15)) * _scaling_adjustment / _dsp_extra_scaling;
229	        const int32_t actual_scalar = static_cast<int32_t>(std::lround(target_scalar));
230	        // Calculate the error introduced by using integer representation for the scalar,
231	        // can be corrected in host later.
232	        _fxpt_scalar_correction = target_scalar / actual_scalar;
233	        // Write DDC with scaling correction for CIC and CORDIC that maximizes dynamic
234	        // range in 32/16/12/8bits.
235	        _iface->poke32(REG_DSP_RX_SCALE_IQ, actual_scalar);
236	    }
237	
238	    double get_scaling_adjustment(void) override
239	    {
240	        return _fxpt_scalar_correction * _host_extra_scaling / 32767.;
241	    }
242	
243	    double set_freq(const double requested_freq) override
244	    {
245	        double actual_freq;
246	        int32_t freq_word;
247	        get_freq_and_freq_word(
248	            requested_freq + _dsp_freq_offset, _tick_rate, actual_freq, freq_word);
249	        _iface->poke32(REG_DSP_RX_FREQ, uint32_t(freq_word));
250	        _current_freq = actual_freq;
251	        return actual_freq;
252	    }
253	
254	    double get_freq(void) override
255	    {
256	        return _current_freq;
257	    }
258	
259	    uhd::meta_range_t get_freq_range(void) override
260	    {
261	        // Too keep the DSP range symmetric about 0, we use abs(_dsp_freq_offset)
262	        const double offset = std::abs(_dsp_freq_offset);
263	        return uhd::meta_range_t(-(_tick_rate - offset) / 2,
264	            +(_tick_rate - offset) / 2,
265	            _tick_rate / std::pow(2.0, 32));
266	    }
267	
268	    void setup(const uhd::stream_args_t& stream_args) override
269	    {
270	        if (stream_args.otw_format == "sc16") {
271	            _dsp_extra_scaling  = 1.0;
272	            _host_extra_scaling = 1.0;
273	        } else if (stream_args.otw_format == "sc8") {
274	            double peak         = stream_args.args.cast<double>("peak", 1.0);
275	            peak                = std::max(peak, 1.0 / 256);
276	            _host_extra_scaling = peak * 256;
277	            _dsp_extra_scaling  = peak;
278	        } else if (stream_args.otw_format == "sc12") {
279	            double peak         = stream_args.args.cast<double>("peak", 1.0);
280	            peak                = std::max(peak, 1.0 / 16);
281	            _host_extra_scaling = peak * 16;
282	            _dsp_extra_scaling  = peak;
283	        } else if (stream_args.otw_format == "fc32") {
284	            _host_extra_scaling = 1.0;
285	            _dsp_extra_scaling  = 1.0;
286	        } else
287	            throw uhd::value_error(
288	                "USRP RX cannot handle requested wire format: " + stream_args.otw_format);
289	
290	        _host_extra_scaling *= stream_args.args.cast<double>("fullscale", 1.0);
291	
292	        this->update_scalar();
293	    }
294	
295	    void populate_subtree(property_tree::sptr subtree) override
296	    {
297	        subtree->create<meta_range_t>("rate/range")
298	            .set_publisher(std::bind(&rx_dsp_core_3000::get_host_rates, this));
299	        subtree->create<double>("rate/value")
300	            .set(DEFAULT_RATE)
301	            .set_coercer(
302	                std::bind(&rx_dsp_core_3000::set_host_rate, this, std::placeholders::_1));
303	        subtree->create<double>("freq/value")
304	            .set(DEFAULT_CORDIC_FREQ)
305	            .set_coercer(
306	                std::bind(&rx_dsp_core_3000::set_freq, this, std::placeholders::_1))
307	            .set_publisher([this]() { return this->get_freq(); });
308	        subtree->create<meta_range_t>("freq/range")
309	            .set_publisher(std::bind(&rx_dsp_core_3000::get_freq_range, this));
310	    }
311	
312	private:
313	    wb_iface::sptr _iface;
314	    const size_t _dsp_base;
315	    const bool _is_b200; // TODO: Obsolete this when we switch to the new DDC on the B200
316	
317	    double _dsp_freq_offset        = 0.0;
318	    double _tick_rate              = 1.0;
319	    double _link_rate              = 0.0;
320	    double _scaling_adjustment     = 1.0;
321	    double _dsp_extra_scaling      = 1.0;
322	    double _host_extra_scaling     = 0.0;
323	    double _fxpt_scalar_correction = 0.0;
324	    double _current_freq           = 0.0;
325	};
326	
327	rx_dsp_core_3000::sptr rx_dsp_core_3000::make(
328	    wb_iface::sptr iface, const size_t dsp_base, const bool is_b200 /* = false */)
329	{
330	    return sptr(new rx_dsp_core_3000_impl(iface, dsp_base, is_b200));
331	}
