90	basic_rx::basic_rx(ctor_args_t args, double max_freq)
91	    : rx_dboard_base(args), _max_freq(max_freq)
92	{
93	    // Examine the frontend to use the RFNoC or the N210 implementation
94	    // (preserves legacy behavior)
95	    const std::string fe_name(get_subdev_name());
96	    const bool is_rfnoc_dev = std::find(rx_frontends.begin(), rx_frontends.end(), fe_name)
97	                              != rx_frontends.end();
98	    const std::string ant_mode(is_rfnoc_dev ? "AB" : fe_name);
99	    const std::string fe_conn(antenna_mode_to_conn[ant_mode]);
100	    const std::string db_name([this]() {
101	        switch (get_rx_id().to_uint16()) {
102	            case BASIC_RX_PID:
103	            case BASIC_RX_RFNOC_PID:
104	                return str(boost::format("%s (%s)") % "BasicRX" % get_subdev_name());
105	            case LF_RX_PID:
106	            case LF_RX_RFNOC_PID:
107	                return str(boost::format("%s (%s)") % "LFRX" % get_subdev_name());
108	            default:
109	                UHD_THROW_INVALID_CODE_PATH();
