115	
116	    std::vector<std::string> antenna_options = antenna_mode_to_conn.keys();
117	
118	    ////////////////////////////////////////////////////////////////////
119	    // Register properties
120	    ////////////////////////////////////////////////////////////////////
121	    this->get_rx_subtree()->create<std::string>("name").set(db_name);
122	    this->get_rx_subtree()->create<std::string>("id").set(
123	        (get_rx_id().to_uint16() & 0xFF) == BASIC_RX_PID ? "basicrx" : "lfrx");
124	    this->get_rx_subtree()->create<int>("gains"); // phony property so this dir exists
125	    this->get_rx_subtree()->create<double>("freq/value").set_publisher([]() {
126	        return 0.0;
127	    });
128	    this->get_rx_subtree()
129	        ->create<meta_range_t>("freq/range")
130	        .set(freq_range_t(-_max_freq, +_max_freq));
131	    this->get_rx_subtree()
132	        ->create<std::string>("antenna/value")
133	        .set(is_rfnoc_dev ? ant_mode : "");
134	    this->get_rx_subtree()
135	        ->create<std::vector<std::string>>("antenna/options")
136	        .set(is_rfnoc_dev ? antenna_options : std::vector<std::string>(1, ""));
137	    this->get_rx_subtree()->create<int>("sensors"); // phony property so this dir exists
138	    this->get_rx_subtree()
139	        ->create<std::string>("connection")
140	        .set(antenna_mode_to_conn[ant_mode]);
141	    this->get_rx_subtree()->create<bool>("enabled").set(true); // always enabled
142	    this->get_rx_subtree()->create<bool>("use_lo_offset").set(false);
143	    this->get_rx_subtree()
144	        ->create<double>("bandwidth/value")
145	        .set(antenna_mode_bandwidth_scalar.at(ant_mode) * _max_freq);
146	    this->get_rx_subtree()
147	        ->create<meta_range_t>("bandwidth/range")
148	        .set(freq_range_t(antenna_mode_bandwidth_scalar.at(ant_mode) * _max_freq,
149	            antenna_mode_bandwidth_scalar.at(ant_mode) * _max_freq));
150	    if (is_rfnoc_dev) {
151	        this->get_rx_subtree()
152	            ->access<std::string>("antenna/value")
153	            .add_coerced_subscriber([this](const std::string& ant) {
154	                this->get_rx_subtree()
155	                    ->access<std::string>("connection")
156	                    .set(antenna_mode_to_conn[ant]);
157	                this->get_rx_subtree()
158	                    ->access<double>("bandwidth/value")
159	                    .set(antenna_mode_bandwidth_scalar.at(ant) * _max_freq);
160	                this->get_rx_subtree()
161	                    ->access<meta_range_t>("bandwidth/range")
162	                    .set(freq_range_t(antenna_mode_bandwidth_scalar.at(ant) * _max_freq,
163	                        antenna_mode_bandwidth_scalar.at(ant) * _max_freq));
164	                UHD_LOG_TRACE("BASICRX",
165	                    "Changing antenna mode on channel: " << get_subdev_name()
166	                                                         << " IQ connection type: "
167	                                                         << antenna_mode_to_conn[ant]);
168	            });
169	    }
170	
171	    // disable RX dboard clock by default
172	    this->get_iface()->set_clock_enabled(dboard_iface::UNIT_RX, false);
173	
174	    // set GPIOs to output 0x0000 to decrease noise pickup
175	    this->get_iface()->set_pin_ctrl(dboard_iface::UNIT_RX, 0x0000);
176	    this->get_iface()->set_gpio_ddr(dboard_iface::UNIT_RX, 0xFFFF);
177	    this->get_iface()->set_gpio_out(dboard_iface::UNIT_RX, 0x0000);
