8	#include <uhd/types/dict.hpp>
9	#include <uhd/types/ranges.hpp>
10	#include <uhd/utils/math.hpp>
11	#include <uhdlib/usrp/cores/dsp_core_utils.hpp>
12	#include <uhdlib/usrp/cores/rx_frontend_core_3000.hpp>
13	#include <cmath>
14	#include <functional>
15	
16	using namespace uhd;
17	
18	#define REG_RX_FE_MAG_CORRECTION   (base + reg_offset * 0) // 18 bits
19	#define REG_RX_FE_PHASE_CORRECTION (base + reg_offset * 1) // 18 bits
20	#define REG_RX_FE_OFFSET_I         (base + reg_offset * 2) // 18 bits
21	#define REG_RX_FE_OFFSET_Q         (base + reg_offset * 3) // 18 bits
22	#define REG_RX_FE_MAPPING          (base + reg_offset * 4)
23	#define REG_RX_FE_HET_CORDIC_PHASE (base + reg_offset * 5)
24	
25	#define FLAG_DSP_RX_MAPPING_SWAP_IQ     (1 << 0)
26	#define FLAG_DSP_RX_MAPPING_REAL_MODE   (1 << 1)
27	#define FLAG_DSP_RX_MAPPING_INVERT_Q    (1 << 2)
28	#define FLAG_DSP_RX_MAPPING_INVERT_I    (1 << 3)
29	#define FLAG_DSP_RX_MAPPING_DOWNCONVERT (1 << 4)
30	//#define FLAG_DSP_RX_MAPPING_RESERVED    (1 << 5)
31	//#define FLAG_DSP_RX_MAPPING_RESERVED    (1 << 6)
32	#define FLAG_DSP_RX_MAPPING_BYPASS_ALL (1 << 7)
33	
34	#define OFFSET_FIXED (1ul << 31)
35	#define OFFSET_SET   (1ul << 30)
36	#define FLAG_MASK    (OFFSET_FIXED | OFFSET_SET)
37	
38	namespace {
39	static const double DC_OFFSET_MIN = -1.0;
40	static const double DC_OFFSET_MAX = 1.0;
41	} // namespace
42	
43	using namespace uhd::usrp;
44	
45	static uint32_t fs_to_bits(const double num, const size_t bits)
46	{
47	    return int32_t(std::lround(num * (1 << (bits - 1))));
48	}
49	
50	rx_frontend_core_3000::~rx_frontend_core_3000(void)
51	{
52	    /* NOP */
53	}
54	
55	const std::complex<double> rx_frontend_core_3000::DEFAULT_DC_OFFSET_VALUE =
56	    std::complex<double>(0.0, 0.0);
57	const bool rx_frontend_core_3000::DEFAULT_DC_OFFSET_ENABLE = true;
58	const std::complex<double> rx_frontend_core_3000::DEFAULT_IQ_BALANCE_VALUE =
59	    std::complex<double>(0.0, 0.0);
60	
61	class rx_frontend_core_3000_impl : public rx_frontend_core_3000
62	{
63	public:
64	    rx_frontend_core_3000_impl(
65	        wb_iface::sptr iface, const size_t base, const size_t reg_offset)
66	        : _i_dc_off(0)
67	        , _q_dc_off(0)
68	        , _adc_rate(0.0)
69	        , _fe_conn(fe_connection_t("IQ"))
70	        , _iface(iface)
71	        , _rx_fe_mag_corr_reg(REG_RX_FE_MAG_CORRECTION)
72	        , _rx_fe_phase_corr_reg(REG_RX_FE_PHASE_CORRECTION)
73	        , _rx_fe_offset_i_reg(REG_RX_FE_OFFSET_I)
74	        , _rx_fe_offset_q_reg(REG_RX_FE_OFFSET_Q)
75	        , _rx_fe_mapping_reg(REG_RX_FE_MAPPING)
76	        , _rx_fe_het_cordic_phase_reg(REG_RX_FE_HET_CORDIC_PHASE)
77	    {
78	        // NOP
79	    }
80	
81	    void set_adc_rate(const double rate) override
82	    {
83	        _adc_rate = rate;
84	    }
85	
86	    void bypass_all(bool bypass_en) override
87	    {
88	        if (bypass_en) {
89	            _iface->poke32(_rx_fe_mapping_reg, FLAG_DSP_RX_MAPPING_BYPASS_ALL);
90	        } else {
91	            set_fe_connection(_fe_conn);
92	        }
93	    }
94	
95	    void set_fe_connection(const fe_connection_t& fe_conn) override
96	    {
97	        uint32_t mapping_reg_val = 0;
98	        switch (fe_conn.get_sampling_mode()) {
99	            case fe_connection_t::REAL:
100	                mapping_reg_val = FLAG_DSP_RX_MAPPING_REAL_MODE;
101	                break;
102	            case fe_connection_t::HETERODYNE:
103	                mapping_reg_val = FLAG_DSP_RX_MAPPING_REAL_MODE
104	                                  | FLAG_DSP_RX_MAPPING_DOWNCONVERT;
105	                break;
106	            default:
107	                mapping_reg_val = 0;
108	                break;
109	        }
110	
111	        if (fe_conn.is_iq_swapped())
112	            mapping_reg_val |= FLAG_DSP_RX_MAPPING_SWAP_IQ;
113	        if (fe_conn.is_i_inverted())
114	            mapping_reg_val |= FLAG_DSP_RX_MAPPING_INVERT_I;
115	        if (fe_conn.is_q_inverted())
116	            mapping_reg_val |= FLAG_DSP_RX_MAPPING_INVERT_Q;
117	
118	        _iface->poke32(_rx_fe_mapping_reg, mapping_reg_val);
119	
120	        UHD_ASSERT_THROW(_adc_rate != 0.0)
121	        if (fe_conn.get_sampling_mode() == fe_connection_t::HETERODYNE) {
122	            // 1. Remember the IF frequency
123	            const double fe_if_freq = fe_conn.get_if_freq();
124	            // 2. Map IF frequency to the range [0, _adc_rate)
125	            double if_freq = std::abs(std::fmod(fe_if_freq, _adc_rate));
126	            // 3. Map IF frequency to the range [-_adc_rate/2, _adc_rate/2]
127	            //   This is the aliased frequency
128	            if (if_freq > (_adc_rate / 2.0)) {
129	                if_freq -= _adc_rate;
130	            }
131	            // 4. Set DSP offset to spin the signal in the opposite
132	            //   direction as the aliased frequency
133	            if (!std::signbit(fe_if_freq)) {
134	                if_freq *= -1.0;
135	            }
136	            const double cordic_freq = if_freq;
137	            UHD_ASSERT_THROW(uhd::math::fp_compare::fp_compare_epsilon<double>(4.0)
138	                             == std::abs(_adc_rate / cordic_freq));
139	
140	            _iface->poke32(_rx_fe_het_cordic_phase_reg, (cordic_freq > 0) ? 0 : 1);
141	        }
142	
143	
144	        _fe_conn = fe_conn;
145	    }
146	
147	    void set_dc_offset_auto(const bool enb) override
148	    {
149	        _set_dc_offset(enb ? 0 : OFFSET_FIXED);
150	    }
151	
152	    std::complex<double> set_dc_offset(const std::complex<double>& off) override
153	    {
154	        static const double scaler = double(1ul << 29);
155	        _i_dc_off = static_cast<int32_t>(std::lround(off.real() * scaler));
156	        _q_dc_off = static_cast<int32_t>(std::lround(off.imag() * scaler));
157	
158	        _set_dc_offset(OFFSET_SET | OFFSET_FIXED);
159	
160	        return std::complex<double>(_i_dc_off / scaler, _q_dc_off / scaler);
161	    }
162	
163	    void _set_dc_offset(const uint32_t flags)
164	    {
165	        _iface->poke32(_rx_fe_offset_i_reg, flags | (_i_dc_off & ~FLAG_MASK));
166	        _iface->poke32(_rx_fe_offset_q_reg, flags | (_q_dc_off & ~FLAG_MASK));
167	    }
168	
169	    void set_iq_balance(const std::complex<double>& cor) override
170	    {
171	        _iface->poke32(_rx_fe_mag_corr_reg, fs_to_bits(cor.real(), 18));
172	        _iface->poke32(_rx_fe_phase_corr_reg, fs_to_bits(cor.imag(), 18));
173	    }
174	
175	    void populate_subtree(uhd::property_tree::sptr subtree) override
176	    {
177	        subtree->create<uhd::meta_range_t>("dc_offset/range")
178	            .set(meta_range_t(DC_OFFSET_MIN, DC_OFFSET_MAX));
179	        subtree->create<std::complex<double>>("dc_offset/value")
180	            .set(DEFAULT_DC_OFFSET_VALUE)
181	            .set_coercer(std::bind(
182	                &rx_frontend_core_3000::set_dc_offset, this, std::placeholders::_1));
183	        subtree->create<bool>("dc_offset/enable")
184	            .set(DEFAULT_DC_OFFSET_ENABLE)
185	            .add_coerced_subscriber(std::bind(
186	                &rx_frontend_core_3000::set_dc_offset_auto, this, std::placeholders::_1));
187	        subtree->create<std::complex<double>>("iq_balance/value")
188	            .set(DEFAULT_IQ_BALANCE_VALUE)
189	            .add_coerced_subscriber(std::bind(
190	                &rx_frontend_core_3000::set_iq_balance, this, std::placeholders::_1));
191	    }
192	
193	private:
194	    int32_t _i_dc_off, _q_dc_off;
195	    double _adc_rate;
196	    fe_connection_t _fe_conn;
197	    wb_iface::sptr _iface;
